const response = $input.first().json;
const accounts = response.accounts || (response.body && response.body.accounts) || [];
if (!accounts.length) throw new Error('No accounts returned from CSM directory API');
return accounts.map(account => ({ json: { account_id: account.account_id, account_name: account.account_name, csm_email: account.csm_email, tier: account.tier || 'standard', stripe_customer_id: account.stripe_customer_id || '', zendesk_org_id: account.zendesk_org_id || account.account_id } }));

const item = $input.first().json;
await new Promise(resolve => setTimeout(resolve, 300));
return [{ json: item }];

const item = $input.first().json;
const ampData = item.data || (item.body && item.body.data) || null;
let amplitude_signals = { available: false, dau_avg: 0, dau_trend: 'unknown', session_count_30d: 0 };
try {
  if (ampData && ampData.data && ampData.data.series) {
    const series = ampData.data.series[0] || [];
    const vals = series.map(function(d) { return d.value || 0; });
    const avg = vals.length ? vals.reduce(function(a,b){ return a+b; }, 0) / vals.length : 0;
    const recent = vals.slice(-7);
    const older = vals.slice(0, 7);
    const recentAvg = recent.length ? recent.reduce(function(a,b){ return a+b; }, 0) / recent.length : 0;
    const olderAvg = older.length ? older.reduce(function(a,b){ return a+b; }, 0) / older.length : 0;
    const trend = recentAvg >= olderAvg * 1.05 ? 'up' : recentAvg <= olderAvg * 0.95 ? 'down' : 'flat';
    amplitude_signals = { available: true, dau_avg: Math.round(avg), dau_trend: trend, session_count_30d: vals.reduce(function(a,b){ return a+b; }, 0) };
  }
} catch(e) {
  amplitude_signals = { available: false, dau_avg: 0, dau_trend: 'unknown', session_count_30d: 0 };
}
return [{ json: Object.assign({}, item, { amplitude_signals: amplitude_signals }) }];

const item = $input.first().json;
const zdResults = item.results || (item.body && item.body.results) || null;
const nextPage = item.next_page || (item.body && item.body.next_page) || null;
let zendesk_signals = { available: false, ticket_count_30d: 0, escalated_count: 0, unresolved_count: 0, escalation_rate: 0, avg_resolution_hrs: 0, zendesk_zero_tickets: false, paginated_truncated: false };
try {
  if (Array.isArray(zdResults)) {
    const tickets = zdResults;
    const escalated = tickets.filter(function(t){ return (t.tags || []).indexOf('escalated') >= 0 || t.priority === 'urgent'; });
    const unresolved = tickets.filter(function(t){ return ['solved','closed'].indexOf(t.status) < 0; });
    const resolved = tickets.filter(function(t){ return t.solved_at && t.created_at; });
    const avgHrs = resolved.length ? resolved.reduce(function(sum, t){ return sum + (new Date(t.solved_at) - new Date(t.created_at)) / 3600000; }, 0) / resolved.length : 0;
    zendesk_signals = { available: true, ticket_count_30d: tickets.length, escalated_count: escalated.length, unresolved_count: unresolved.length, escalation_rate: tickets.length ? Math.round(escalated.length / tickets.length * 100) : 0, avg_resolution_hrs: Math.round(avgHrs), zendesk_zero_tickets: tickets.length === 0, paginated_truncated: !!nextPage };
  }
} catch(e) {
  zendesk_signals = { available: false, ticket_count_30d: 0, escalated_count: 0, unresolved_count: 0, escalation_rate: 0, avg_resolution_hrs: 0, zendesk_zero_tickets: false, paginated_truncated: false };
}
return [{ json: Object.assign({}, item, { zendesk_signals: zendesk_signals }) }];

const item = $input.first().json;
const hasStripe = typeof item.stripe_customer_id === 'string' && item.stripe_customer_id.trim().length > 0;
return [{ json: Object.assign({}, item, { has_stripe_customer_id: hasStripe }) }];

const item = $input.first().json;
const stripeData = item.data || (item.body && item.body.data) || null;
let stripe_signals = { available: false, mrr: 0, mrr_source: 'unavailable', subscription_status: 'unknown', payment_failures_detected: 0, payment_failures_note: 'data unavailable', in_dunning: false, cancel_at_period_end: false };
try {
  if (Array.isArray(stripeData) && stripeData.length) {
    const sub = stripeData[0];
    const inv = sub.latest_invoice || {};
    const piFailure = inv.payment_intent && inv.payment_intent.last_payment_error ? 1 : 0;
    const metaFailures = sub.metadata && sub.metadata.payment_failure_count ? parseInt(sub.metadata.payment_failure_count) : 0;
    // MRR: prefer items.data[0].price.unit_amount (current API), fallback to deprecated plan.amount
    let mrr = 0;
    let mrrSource = 'unavailable';
    if (sub.items && sub.items.data && sub.items.data[0] && sub.items.data[0].price && sub.items.data[0].price.unit_amount != null) {
      mrr = Math.round(sub.items.data[0].price.unit_amount / 100);
      mrrSource = 'items.price';
    } else if (sub.plan && sub.plan.amount != null) {
      mrr = Math.round(sub.plan.amount / 100);
      mrrSource = 'plan_deprecated';
    }
    stripe_signals = { available: true, mrr: mrr, mrr_source: mrrSource, subscription_status: sub.status || 'unknown', payment_failures_detected: piFailure + metaFailures, payment_failures_note: 'proxy metric from latest invoice; not a full 90-day history', in_dunning: sub.status === 'past_due', cancel_at_period_end: sub.cancel_at_period_end || false };
  }
} catch(e) {
  stripe_signals = { available: false, mrr: 0, mrr_source: 'unavailable', subscription_status: 'unknown', payment_failures_detected: 0, payment_failures_note: 'parse error', in_dunning: false, cancel_at_period_end: false };
}
return [{ json: Object.assign({}, item, { stripe_signals: stripe_signals }) }];

const item = $input.first().json;
const amp = item.amplitude_signals && item.amplitude_signals.available === true;
const zd = item.zendesk_signals && item.zendesk_signals.available === true;
const stripe = item.stripe_signals && item.stripe_signals.available === true;
const sources_available = [amp, zd, stripe].filter(Boolean).length;
const has_minimum_data = sources_available >= 2;
return [{ json: Object.assign({}, item, { sources_available: sources_available, has_minimum_data: has_minimum_data }) }];

const item = $input.first().json;
let llm_valid = false;
let health_score = null;
let headline = '';
let suggestions = [];
try {
  const content = item.choices && item.choices[0] && item.choices[0].message && item.choices[0].message.content ? item.choices[0].message.content : '{}';
  const parsed = JSON.parse(content);
  health_score = parseInt(parsed.score);
  headline = parsed.headline || '';
  suggestions = Array.isArray(parsed.suggestions) ? parsed.suggestions : [];
  llm_valid = Number.isInteger(health_score) && health_score >= 0 && health_score <= 100 && headline.length > 0 && suggestions.length >= 2 && suggestions.length <= 3;
} catch(e) {
  llm_valid = false;
}
const severity = health_score !== null && Number.isInteger(health_score) ? (health_score <= 39 ? 'critical' : health_score <= 69 ? 'at_risk' : 'healthy') : 'unknown';
return [{ json: { account_id: item.account_id, account_name: item.account_name, csm_email: item.csm_email, tier: item.tier, amplitude_signals: item.amplitude_signals, zendesk_signals: item.zendesk_signals, stripe_signals: item.stripe_signals, health_score: health_score, headline: headline, suggestions: suggestions, severity: severity, llm_valid: llm_valid } }];

const item = $input.first().json;
const score = item.health_score;
const is_critical = score <= 39;
const is_at_risk = score >= 40 && score <= 69;
const is_healthy = score >= 70;
const should_alert = is_critical || is_at_risk;
return [{ json: Object.assign({}, item, { is_critical: is_critical, is_at_risk: is_at_risk, is_healthy: is_healthy, should_alert: should_alert }) }];

const item = $input.first().json;
const staticData = $workflow.staticData;
if (!staticData.alertLog) staticData.alertLog = {};
const now = Date.now();
const accountKey = item.account_id;
const lastAlerted = staticData.alertLog[accountKey] ? staticData.alertLog[accountKey].last_alerted : 0;
const cooldownMs = item.is_critical ? 24 * 60 * 60 * 1000 : 48 * 60 * 60 * 1000;
const withinCooldown = (now - lastAlerted) < cooldownMs;
let cooldown_suppressed = false;
if (item.should_alert) {
  if (withinCooldown) {
    cooldown_suppressed = true;
  } else {
    // Update last_alerted for this account
    staticData.alertLog[accountKey] = { last_alerted: now, severity: item.severity };
  }
}
return [{ json: Object.assign({}, item, { cooldown_suppressed: cooldown_suppressed, last_alerted_ts: lastAlerted }) }];
